    std::env::args_os()
        .next()
        .and_then(|s| s.into_string().ok())
        .and_then(|s| PathBuf::from(s).file_name().map(|s| s.to_string_lossy().to_string()))
        .unwrap_or_else(|| "modelmux".to_string())
}

